import{_ as r,c as i,o,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.2.1: Cross-Directory Session Viewing","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.2.1.md","filePath":"en/changelog/v1.2.1.md","lastUpdated":1772014034000}'),s={name:"en/changelog/v1.2.1.md"};function n(l,a,h,c,d,p){return o(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-2-1-cross-directory-session-viewing" tabindex="-1">v1.2.1: Cross-Directory Session Viewing <a class="header-anchor" href="#v1-2-1-cross-directory-session-viewing" aria-label="Permalink to “v1.2.1: Cross-Directory Session Viewing”">​</a></h1><p><strong>Release Date</strong>: February 14, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update lets you <strong>view session records from all projects from any directory</strong>, and optimizes web search caching behavior.</p><hr><h2 id="new-feature-view-all-sessions-across-directories" tabindex="-1">New Feature: View All Sessions Across Directories <a class="header-anchor" href="#new-feature-view-all-sessions-across-directories" aria-label="Permalink to “New Feature: View All Sessions Across Directories”">​</a></h2><h3 id="the-previous-problem" tabindex="-1">The Previous Problem <a class="header-anchor" href="#the-previous-problem" aria-label="Permalink to “The Previous Problem”">​</a></h3><p>You might use OpenCode across multiple project directories, each with its own sessions. Previously, to view sessions for a specific project, you had to <code>cd</code> to that directory first.</p><h3 id="the-current-situation" tabindex="-1">The Current Situation <a class="header-anchor" href="#the-current-situation" aria-label="Permalink to “The Current Situation”">​</a></h3><p><strong>You can see sessions from all projects from any directory</strong>. No matter where you are, OpenCode will list all your project session records.</p><h3 id="what-are-the-benefits" tabindex="-1">What are the benefits? <a class="header-anchor" href="#what-are-the-benefits" aria-label="Permalink to “What are the benefits?”">​</a></h3><ul><li>No need to frequently switch directories</li><li>Quickly find previous conversations</li><li>Easier multi-project management</li></ul><hr><h2 id="optimization-web-search-saves-bandwidth" tabindex="-1">Optimization: Web Search Saves Bandwidth <a class="header-anchor" href="#optimization-web-search-saves-bandwidth" aria-label="Permalink to “Optimization: Web Search Saves Bandwidth”">​</a></h2><h3 id="what-changed" tabindex="-1">What changed? <a class="header-anchor" href="#what-changed" aria-label="Permalink to “What changed?”">​</a></h3><p>Fine-tuned the date information description in the <code>websearch</code> tool to avoid bypassing cache on every search.</p><h3 id="how-does-it-affect-you" tabindex="-1">How does it affect you? <a class="header-anchor" href="#how-does-it-affect-you" aria-label="Permalink to “How does it affect you?”">​</a></h3><ul><li>Faster search response (when cached)</li><li>Reduced API calls</li><li>Overall bandwidth savings</li></ul><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Frequently switch between projects</td><td>✅ Upgrade</td></tr><tr><td>Want better session management</td><td>✅ Upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next release</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',23),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-optional" tabindex="-1">Technical Details (Optional) <a class="header-anchor" href="#technical-details-optional" aria-label="Permalink to “Technical Details (Optional)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Display all project sessions from any working directory</li><li>Fine-tuned websearch tool date information description to avoid cache invalidation</li></ul><h3 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to “Notes”">​</a></h3><p>This version shares the same data migration logic (SQLite) as v1.2.0, which runs automatically on first launch.</p></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const b=r(s,[["render",n]]);export{m as __pageData,b as default};
